"use strict";
// UXP runtime polyfills. MUST be the first entry in the webpack build so these
// globals exist before any dependency (notably @anthropic-ai/sdk) is imported —
// the SDK calls `new TextEncoder()` at module top-level, which throws in UXP
// because UXP's JS engine does not expose TextEncoder/TextDecoder globally.
const g = globalThis;
if (typeof g.TextEncoder === 'undefined') {
    // Minimal UTF-8 encoder (string → Uint8Array).
    g.TextEncoder = class TextEncoder {
        constructor() {
            this.encoding = 'utf-8';
        }
        encode(input = '') {
            const str = unescape(encodeURIComponent(input)); // → Latin-1 bytes of UTF-8
            const bytes = new Uint8Array(str.length);
            for (let i = 0; i < str.length; i++)
                bytes[i] = str.charCodeAt(i);
            return bytes;
        }
        encodeInto(input, dest) {
            const encoded = this.encode(input);
            const written = Math.min(encoded.length, dest.length);
            dest.set(encoded.subarray(0, written));
            return { read: input.length, written };
        }
    };
}
